import React from 'react';
import { motion } from 'framer-motion';
import { 
  FaCogs, FaOilCan, FaCarBattery, FaSnowflake, 
  FaCarCrash, FaLaptopMedical, FaTachometerAlt 
} from 'react-icons/fa';
import './Services.css';

const Services = () => {
  const services = [
    {
      icon: <FaCogs />,
      title: 'Engine Repair',
      desc: 'Complete engine diagnostics and repair services using advanced tools and genuine parts.',
      color: '#ff4d2d',
    },
    {
      icon: <FaOilCan />,
      title: 'Oil Change',
      desc: 'Premium synthetic and conventional oil changes to keep your engine running smoothly.',
      color: '#ff6b4a',
    },
    {
      icon: <FaCarCrash />,
      title: 'Brake Service',
      desc: 'Full brake inspection, pad replacement, and rotor resurfacing for maximum safety.',
      color: '#ff8c6b',
    },
    {
      icon: <FaSnowflake />,
      title: 'Air Conditioning',
      desc: 'AC system inspection, refrigerant recharge, and compressor repair services.',
      color: '#4ecdc4',
    },
    {
      icon: <FaCarBattery />,
      title: 'Battery Replacement',
      desc: 'Battery testing and replacement with high-quality brands for reliable starts.',
      color: '#ffd700',
    },
    {
      icon: <FaLaptopMedical />,
      title: 'Diagnostics',
      desc: 'Advanced computerized diagnostics to identify and resolve vehicle issues quickly.',
      color: '#a855f7',
    },
    {
      icon: <FaTachometerAlt />,
      title: 'Tire & Alignment',
      desc: 'Professional tire fitting, balancing, and wheel alignment services.',
      color: '#06b6d4',
    },
  ];

  return (
    <section id="services" className="services">
      <div className="services-container">
        <motion.div
          className="section-header"
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6 }}
        >
          <span className="section-tag">What We Offer</span>
          <h2 className="section-title">
            Our <span className="text-accent">Services</span>
          </h2>
          <p className="section-desc">
            Comprehensive auto repair and maintenance solutions
          </p>
        </motion.div>

        <div className="services-grid">
          {services.map((service, index) => (
            <motion.div
              key={service.title}
              className="service-card"
              initial={{ opacity: 0, y: 40 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              whileHover={{ y: -10 }}
            >
              <div
                className="service-icon-wrapper"
                style={{ 
                  background: `rgba(${hexToRgb(service.color)}, 0.1)`,
                  borderColor: service.color 
                }}
              >
                <span style={{ color: service.color }}>{service.icon}</span>
              </div>
              <h3 className="service-title">{service.title}</h3>
              <p className="service-desc">{service.desc}</p>
              <div
                className="service-glow"
                style={{ background: service.color }}
              ></div>
            </motion.div>
          ))}
        </div>
      </div>
      
      <div className="section-divider"></div>
    </section>
  );
};

function hexToRgb(hex) {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result
    ? `${parseInt(result[1], 16)}, ${parseInt(result[2], 16)}, ${parseInt(result[3], 16)}`
    : '255, 77, 45';
}

export default Services;
